function getRisk(canonicalToolId: string): string {
  if (trademarkTools.has(canonicalToolId)) return 'Trademark and availability review required before public or commercial use.';
  if (platformTools.has(canonicalToolId)) return 'Avoid platform guarantees, ranking promises, virality claims, or misleading tags.';
  if (technicalTools.has(canonicalToolId)) return 'Technical SEO output should be reviewed before production use.';
  if (accessibilityTools.has(canonicalToolId)) return 'Check readability, accessibility, and platform compatibility before sharing.';
  if (factualTools.has(canonicalToolId)) return 'Review factual claims, originality, compliance, and project rules before publishing.';
  if (ipTools.has(canonicalToolId)) return 'Avoid protected franchise names, celebrities, and recognizable third-party IP.';
  return defaultRisk;
}

function formatMetaDescription(language: NewPilotLanguage, base: string, h1: string, keyword: string): string {
  if (language === 'pt') return `${base} Use ${h1} para obter rascunhos alinhados a ${keyword}.`;
  if (language === 'it') return `${base} Usa ${h1} per ottenere bozze coerenti con ${keyword}.`;
  return `${base} Użyj ${h1}, aby otrzymać szkice zgodne z intencją: ${keyword}.`;
}

function formatMetaTitle(language: NewPilotLanguage, h1: string): string {
  if (language === 'pl') return `Darmowe narzędzie: ${h1}`;
  return `${h1} ${freeWord[language]}`;
}

function formatNextMetaDescription(language: NextPilotLanguage, base: string, h1: string, keyword: string): string {
  if (language === 'ru') return `${base} Используйте ${h1}, чтобы получить черновики под запрос «${keyword}».`;
  if (language === 'tr') return `${base} ${h1} ile ${keyword} amacına uygun taslaklar alın.`;
  return `${base} Gunakan ${h1} untuk membuat draf yang sesuai dengan maksud ${keyword}.`;
}

function formatNextMetaTitle(language: NextPilotLanguage, h1: string): string {
  return `${h1} ${nextFreeWord[language]}`;
}

function formatThirdMetaDescription(language: ThirdPilotLanguage, base: string, h1: string, keyword: string): string {
  if (language === 'sv') return `${base} Anvand ${h1} for att skapa utkast som matchar ${keyword}.`;
  if (language === 'ms') return `${base} Gunakan ${h1} untuk mencipta draf yang selaras dengan maksud ${keyword}.`;
  return `${base} Използвайте ${h1}, за да получите чернови според заявката "${keyword}".`;
}

function formatThirdMetaTitle(language: ThirdPilotLanguage, h1: string): string {
  return `${h1} ${thirdFreeWord[language]}`;
}

function formatFourthMetaDescription(language: FourthPilotLanguage, base: string, h1: string, keyword: string): string {
  if (language === 'hi') return `${base} ${h1} का उपयोग करके ${keyword} इरादे के अनुसार मसौदे बनाएं.`;
  if (language === 'bn') return `${base} ${h1} ব্যবহার করে ${keyword} উদ্দেশ্যের সঙ্গে মিল থাকা খসড়া তৈরি করুন.`;
  if (language === 'ja') return `${base} ${h1}で「${keyword}」の意図に合う下書きを作成します.`;
  if (language === 'ko') return `${base} ${h1}로 ${keyword} 의도에 맞는 초안을 만드세요.`;
  return `${base} استخدم ${h1} لإنشاء مسودات مناسبة لقصد ${keyword}.`;
}

function formatFourthMetaTitle(language: FourthPilotLanguage, h1: string): string {
  return `${h1} ${fourthFreeWord[language]}`;
}

const priorLocalizedPilotToolData: LocalizedToolContent[] = translations.flatMap((item) =>
  (['pt', 'it', 'pl'] as const).map((language) => {
    const copy = item[language];
    const kind = kindCopy[language][item.kind];
    return {
      canonicalToolId: item.canonicalToolId,
      language,
      primaryKeyword: copy.primaryKeyword,
      localizedSlug: copy.localizedSlug,
      h1: copy.h1,
      metaTitle: formatMetaTitle(language, copy.h1),
      metaDescription: formatMetaDescription(language, kind.meta, copy.h1, copy.primaryKeyword),
      intro: kind.intro,
      faqTopics: copy.faqTopics,
      searchIntentNote: kind.intent,
      riskSafetyNote: getRisk(item.canonicalToolId),
    };
  }),
);

